import ldap3

def search_user(username, hostname, port, basedn):
    server = ldap3.Server(hostname, port=port)
    conn = ldap3.Connection(server, user='cn=admin,dc=example,dc=com', password='password')
    conn.bind()
    
    filter = '(uid={})'.format(username)
    attributes = ['*']
    p = ldap3.protocol.LDAPSearchResult(conn, basedn=basedn, filter=filter, attributes=attributes)
    
    for entry in p.response:
        if 'dn' in entry and entry['dn'] != b'' and entry['dn'] != '':
            return entry
    return None

